26	namespace {
27	/*************************************************************************
28	 * Local constants
29	 ************************************************************************/
30	//! Most pessimistic time for a CHDR query to go to device and back
31	const double MPMD_CHDR_MAX_RTT = 0.02;
32	//! MPM Compatibility number {MAJOR, MINOR}
33	const std::vector<size_t> MPM_COMPAT_NUM = {6, 1};
34	
35	/*************************************************************************
36	 * Helper functions
37	 ************************************************************************/
38	void reset_time_synchronized(uhd::property_tree::sptr tree)
39	{
40	    const size_t n_mboards = tree->list("/mboards").size();
41	    UHD_LOGGER_DEBUG("MPMD") << "Synchronizing " << n_mboards << " timekeepers...";
42	    auto get_time_last_pps = [tree]() {
43	        return tree->access<time_spec_t>(fs_path("/mboards/0/time/pps")).get();
44	    };
45	    auto end_time = std::chrono::steady_clock::now() + std::chrono::milliseconds(1100);
46	    auto time_last_pps = get_time_last_pps();
47	    UHD_LOG_DEBUG("MPMD", "Waiting for PPS clock edge...");
48	    while (time_last_pps == get_time_last_pps()) {
49	        if (std::chrono::steady_clock::now() > end_time) {
50	            throw uhd::runtime_error("Board 0 may not be getting a PPS signal!\n"
51	                                     "No PPS detected within the time interval.\n"
52	                                     "See the application notes for your device.\n");
53	        }
54	        std::this_thread::sleep_for(std::chrono::milliseconds(10));
55	    }
56	    UHD_LOG_DEBUG("MPMD", "Setting all timekeepers to 0...");
57	    for (size_t mboard_idx = 0; mboard_idx < n_mboards; mboard_idx++) {
58	        tree->access<time_spec_t>(fs_path("/mboards") / mboard_idx / "time" / "pps")
59	            .set(time_spec_t(0.0));
60	    }
61	
62	    UHD_LOG_DEBUG("MPMD", "Waiting for next PPS edge...");
63	    std::this_thread::sleep_for(std::chrono::seconds(1));
64	
65	    UHD_LOG_DEBUG("MPMD", "Verifying all timekeepers are aligned...");
66	    auto get_time_now = [tree](const size_t mb_index) {
67	        return tree->access<time_spec_t>(fs_path("/mboards") / mb_index / "time/now")
68	            .get();
69	    };
70	    for (size_t m = 1; m < n_mboards; m++) {
71	        time_spec_t time_0 = get_time_now(0);
72	        time_spec_t time_i = get_time_now(m);
73	        if (time_i < time_0 or (time_i - time_0) > time_spec_t(MPMD_CHDR_MAX_RTT)) {
74	            UHD_LOGGER_WARNING("MULTI_USRP")
75	                << boost::format("Detected time deviation between board %d and board 0.\n"
76	                                 "Board 0 time is %f seconds.\n"
77	                                 "Board %d time is %f seconds.\n")
78	                       % m % time_0.get_real_secs() % m % time_i.get_real_secs();
79	        }
80	    }
81	}
82	
83	/*! Throw an exception if compat numbers don't match.
84	 *
85	 * \param component Name of the component for which we're checking the
86	 *                  compat number (for logging and exceptions strings).
87	 * \param expected Tuple of 2 integers representing MAJOR.MINOR compat
88	 *                 number.
89	 * \param actual Tuple of 2 integers representing MAJOR.MINOR compat
90	 *                 number.
91	 * \param advice_on_failure A string that is appended to the error message
92	 *                          when compat number mismatches have occurred.
93	 */
94	void assert_compat_number_throw(const std::string& component,
95	    const std::vector<size_t>& expected,
96	    const std::vector<size_t>& actual,
97	    const std::string& advice_on_failure = "")
98	{
99	    UHD_ASSERT_THROW(expected.size() == 2);
100	    UHD_ASSERT_THROW(actual.size() == 2);
101	    UHD_LOGGER_TRACE("MPMD") << "Checking " << component
102	                             << " compat number. Expected: " << expected[0] << "."
103	                             << expected[1] << " Actual: " << actual[0] << "."
104	                             << actual[1];
105	
106	    if (actual[0] != expected[0]) {
107	        const std::string err_msg =
108	            str(boost::format("%s major compat number mismatch. "
109	                              "Expected: %i.%i Actual: %i.%i.%s%s")
110	                % component % expected[0] % expected[1] % actual[0] % actual[1]
111	                % (advice_on_failure.empty() ? "" : " ") % advice_on_failure);
112	        UHD_LOG_ERROR("MPMD", err_msg);
113	        throw uhd::runtime_error(err_msg);
114	    }
115	    if (actual[1] < expected[1]) {
116	        const std::string err_msg =
117	            str(boost::format("%s minor compat number mismatch. "
118	                              "Expected: %i.%i Actual: %i.%i.%s%s")
119	                % component % expected[0] % expected[1] % actual[0] % actual[1]
120	                % (advice_on_failure.empty() ? "" : " ") % advice_on_failure);
121	        UHD_LOG_ERROR("MPMD", err_msg);
122	        throw uhd::runtime_error(err_msg);
123	    }
124	    if (actual[1] > expected[1]) {
125	        const std::string err_msg =
126	            str(boost::format("%s minor compat number mismatch. "
127	                              "Expected: %i.%i Actual: %i.%i")
128	                % component % expected[0] % expected[1] % actual[0] % actual[1]);
129	        UHD_LOG_WARNING("MPMD", err_msg);
130	    }
131	}
132	} // namespace
133	
134	/*****************************************************************************
135	 * Static class attributes
136	 ****************************************************************************/
137	const std::string mpmd_impl::MPM_FINDALL_KEY            = "find_all";
138	const size_t mpmd_impl::MPM_DISCOVERY_PORT              = 49600;
139	const std::string mpmd_impl::MPM_DISCOVERY_PORT_KEY     = "discovery_port";
140	const size_t mpmd_impl::MPM_RPC_PORT                    = 49601;
141	const std::string mpmd_impl::MPM_RPC_PORT_KEY           = "rpc_port";
142	const std::string mpmd_impl::MPM_RPC_GET_LAST_ERROR_CMD = "get_last_error";
143	const std::string mpmd_impl::MPM_DISCOVERY_CMD          = "MPM-DISC";
144	const std::string mpmd_impl::MPM_ECHO_CMD               = "MPM-ECHO";
145	
146	/*****************************************************************************
147	 * Structors
148	 ****************************************************************************/
149	mpmd_impl::mpmd_impl(const device_addr_t& device_args)
150	    : rfnoc_device(), _device_args(device_args)
151	{
152	    const device_addrs_t mb_args_without_prefs = separate_device_addr(device_args);
153	    device_addrs_t mb_args;
154	    for (size_t i = 0; i < mb_args_without_prefs.size(); ++i) {
155	        mb_args.push_back(prefs::get_usrp_args(mb_args_without_prefs[i]));
156	        UHD_ASSERT_THROW(mb_args.back().has_key(RPC_VERSION_KEY));
157	        if (mb_args.back().get(RPC_VERSION_KEY) != RPC_VERSION) {
158	            UHD_LOG_THROW(uhd::runtime_error,
159	                "MPMD",
160	                "RPC version mismatch on device "
161	                    << mb_args.back().to_string() << ". Expected: " << RPC_VERSION
162	                    << " Actual: " << device_args.get(RPC_VERSION_KEY)
163	                    << ". Please align the version of MPM on your USRP device to the "
164	                       "host driver version.");
165	        }
166	    }
167	    const size_t num_mboards = mb_args.size();
168	    _mb.reserve(num_mboards);
169	    const bool serialize_init = device_args.has_key("serialize_init");
170	    const bool skip_init      = device_args.has_key("skip_init");
171	    UHD_LOGGER_INFO("MPMD") << "Initializing " << num_mboards << " device(s) "
172	                            << (serialize_init ? "serially " : "in parallel ")
173	                            << "with args: " << device_args.to_string();
174	
175	    // First, claim all the devices (so we own them and no one else can claim
176	    // them).
177	    // This can be parallelized as long as uptrs are stored in the right spot;
178	    // they need to be correctly indexed.
179	    for (size_t mb_i = 0; mb_i < num_mboards; ++mb_i) {
180	        UHD_LOG_DEBUG("MPMD", "Claiming mboard " << mb_i);
181	        _mb.push_back(claim_and_make(mb_args[mb_i]));
182	    }
183	
184	    if (not skip_init) {
185	        // Run the actual device initialization. This can run in parallel.
186	        for (size_t mb_i = 0; mb_i < num_mboards; ++mb_i) {
187	            // Note: This is the only place we do compat number checks. They're
188	            // effectively disabled for skip_init=1
189	            setup_mb(_mb[mb_i].get(), mb_i);
190	        }
191	    } else {
192	        UHD_LOG_DEBUG("MPMD", "Claimed device, but skipped init.");
193	    }
194	
195	    // Init the prop tree before the blocks get set up -- they might need access
196	    // to some of the properties. This also means that the prop tree is pristine
197	    // at this point in time.
198	    // This might be parallelized, need to verify the prop tree can handle the
199	    // concurrent accesses. Would shave of milliseconds per device -- probably
200	    // not worth it.
201	    for (size_t mb_i = 0; mb_i < mb_args.size(); ++mb_i) {
202	        init_property_tree(_tree, fs_path("/mboards") / mb_i, _mb[mb_i].get());
203	    }
204	
205	    if (not skip_init) {
206	        // FIXME this section only makes sense for when the time source is external.
207	        // So, check for that, or something similar.
208	        // This section of code assumes that the prop tree is set and we have access
209	        // to the timekeepers. So don't move it anywhere else.
210	        if (device_args.has_key("sync_time")) {
211	            reset_time_synchronized(_tree);
212	        }
213	    } else {
214	        UHD_LOG_INFO("MPMD", "Claimed device without full initialization.");
215	    }
216	}
217	
218	mpmd_impl::~mpmd_impl()
219	{
220	    _deinit();
221	}
222	
223	/*****************************************************************************
224	 * Protected methods
225	 ****************************************************************************/
226	void mpmd_impl::_deinit()
227	{
228	    _tree.reset();
229	    _mb.clear();
230	}
231	
232	/*****************************************************************************
233	 * Private methods
234	 ****************************************************************************/
235	mpmd_mboard_impl::uptr mpmd_impl::claim_and_make(const uhd::device_addr_t& device_args)
236	{
237	    const std::string rpc_addr = device_args.get(MGMT_ADDR_KEY);
238	    UHD_LOGGER_DEBUG("MPMD") << "Device args: `" << device_args.to_string()
239	                             << "'. RPC address: " << rpc_addr;
240	
241	    if (rpc_addr.empty()) {
242	        UHD_LOG_ERROR("MPMD",
243	            "Could not determine RPC address from device args: "
244	                << device_args.to_string());
245	        throw uhd::runtime_error("Could not determine device RPC address.");
246	    }
247	    return mpmd_mboard_impl::make(device_args, rpc_addr);
248	}
249	
250	void mpmd_impl::setup_mb(mpmd_mboard_impl* mb, const size_t mb_index)
251	{
252	    assert_compat_number_throw("MPM",
253	        MPM_COMPAT_NUM,
254	        mb->rpc->request<std::vector<size_t>>("get_mpm_compat_num"),
255	        "Please update the version of MPM on your USRP device.");
256	
257	    UHD_LOG_DEBUG("MPMD", "Initializing mboard " << mb_index);
258	    mb->init();
259	    UHD_ASSERT_THROW(mb->mb_ctrl);
260	    register_mb_controller(mb_index, mb->mb_ctrl);
261	}
262	
263	/*****************************************************************************
264	 * Factory & Registry
265	 ****************************************************************************/
266	static device::sptr mpmd_make(const device_addr_t& device_args)
267	{
268	    return device::sptr(std::make_shared<mpmd_impl>(device_args));
269	}
270	
271	UHD_STATIC_BLOCK(register_mpmd_device)
272	{
273	    device::register_device(&mpmd_find, &mpmd_make, device::USRP);
274	}
