7	// find-related code for MPM devices
8	
9	#include "mpmd_devices.hpp"
10	#include "mpmd_impl.hpp"
11	#include "mpmd_link_if_mgr.hpp"
12	#include <uhd/transport/if_addrs.hpp>
13	#include <uhd/transport/udp_simple.hpp>
14	#include <uhd/types/device_addr.hpp>
15	#include <uhd/utils/cast.hpp>
16	#include <uhdlib/asio.hpp>
17	#include <uhdlib/utils/prefs.hpp>
18	#include <uhdlib/utils/serial_number.hpp>
19	#include <boost/algorithm/string.hpp>
20	#include <algorithm>
21	#include <future>
22	#include <iterator>
23	#ifdef HAVE_DPDK
24	#    include <uhdlib/transport/dpdk/common.hpp>
25	#endif
26	
27	using namespace uhd;
28	using namespace uhd::mpmd;
29	
30	namespace {
31	//! How long we wait for discovery responses (in seconds)
32	constexpr double MPMD_FIND_TIMEOUT               = 0.5;
33	constexpr char MPMD_CHDR_REACHABILITY_KEY[]      = "reachable";
34	constexpr char MPMD_CHDR_REACHABILITY_NEGATIVE[] = "No";
35	//! The preamble for any response on the discovery port. Can be used to
36	//  verify that the response is actually an MPM device.
37	constexpr char MPM_DISC_RESPONSE_PREAMBLE[] = "USRP-MPM";
38	
39	device_addr_t flag_dev_as_unreachable(const device_addr_t& device_args)
40	{
41	    device_addr_t flagged_device_args(device_args);
42	    flagged_device_args[MPMD_CHDR_REACHABILITY_KEY] = MPMD_CHDR_REACHABILITY_NEGATIVE;
43	    return flagged_device_args;
44	}
45	} // namespace
46	
47	device_addrs_t mpmd_find_with_addr(
48	    const std::string& mgmt_addr, const device_addr_t& hint_)
49	{
50	    UHD_ASSERT_THROW(not mgmt_addr.empty());
51	    const std::string mpm_discovery_port = hint_.get(
52	        mpmd_impl::MPM_DISCOVERY_PORT_KEY, std::to_string(mpmd_impl::MPM_DISCOVERY_PORT));
53	    UHD_LOG_DEBUG("MPMD", "Discovering MPM devices on port " << mpm_discovery_port);
54	
55	    device_addrs_t addrs;
56	    transport::udp_simple::sptr comm =
57	        transport::udp_simple::make_broadcast(mgmt_addr, mpm_discovery_port);
58	    comm->send(boost::asio::buffer(
59	        mpmd_impl::MPM_DISCOVERY_CMD.c_str(), mpmd_impl::MPM_DISCOVERY_CMD.size()));
60	    while (true) {
61	        const size_t MAX_MTU = 8000;
62	        char buff[MAX_MTU]   = {};
63	        const size_t nbytes =
64	            comm->recv(boost::asio::buffer(buff, MAX_MTU), MPMD_FIND_TIMEOUT);
65	        if (nbytes == 0) {
66	            break;
67	        }
68	        const char* reply        = (const char*)buff;
69	        std::string reply_string = std::string(reply);
70	        std::vector<std::string> result;
71	        boost::algorithm::split(
72	            result,
73	            reply_string,
74	            [](const char& in) { return in == ';'; },
75	            boost::token_compress_on);
76	        if (result.empty()) {
77	            continue;
78	        }
79	        // Verify we didn't receive something other than an MPM discovery
80	        // response
81	        if (result[0] != MPM_DISC_RESPONSE_PREAMBLE) {
82	            continue;
83	        }
84	        const std::string recv_addr = comm->get_recv_addr();
85	
86	        // remove external iface addrs if executed directly on device
87	        bool external_iface = false;
88	        for (const auto& addr : transport::get_if_addrs()) {
89	            if ((addr.inet == comm->get_recv_addr())
90	                && recv_addr != boost::asio::ip::address_v4::loopback().to_string()) {
91	                external_iface = true;
92	                break;
93	            }
94	        }
95	        if (external_iface) {
96	            continue;
97	        }
98	
99	        // Create result to return
100	        device_addr_t new_addr;
101	        new_addr[MGMT_ADDR_KEY] = recv_addr;
102	        new_addr["type"]        = "mpmd"; // hwd will overwrite this
103	        // remove ident string and put other informations into device_args dict
104	        result.erase(result.begin());
105	        // parse key-value pairs in the discovery string and add them to the
106	        // device_args
107	        for (const auto& el : result) {
108	            std::vector<std::string> value;
109	            boost::algorithm::split(
110	                value,
111	                el,
112	                [](const char& in) { return in == '='; },
113	                boost::token_compress_on);
114	            if (value[0] != MGMT_ADDR_KEY) {
115	                new_addr[value[0]] = value[1];
116	            }
117	        }
118	        new_addr[RPC_VERSION_KEY] = new_addr.get(RPC_VERSION_KEY, DEFAULT_RPC_VERSION);
119	        addrs.push_back(new_addr);
120	    }
121	    return addrs;
122	};
123	
124	
125	// Implements scenario 1) (see below)
126	device_addrs_t mpmd_find_with_addrs(const device_addrs_t& hints)
127	{
128	    UHD_LOG_TRACE("MPMD FIND", "Finding with addrs.");
129	    device_addrs_t found_devices;
130	    found_devices.reserve(hints.size());
131	    for (const auto& hint : hints) {
132	        if (hint.has_key("resource")) {
133	            continue;
134	        }
135	        if (not(hint.has_key(xport::FIRST_ADDR_KEY) or hint.has_key(MGMT_ADDR_KEY))) {
136	            UHD_LOG_DEBUG("MPMD FIND", "No address given in hint " << hint.to_string());
137	            continue;
138	        }
139	        const std::string mgmt_addr =
140	            hint.get(MGMT_ADDR_KEY, hint.get(xport::FIRST_ADDR_KEY, ""));
141	        device_addrs_t reply_addrs = mpmd_find_with_addr(mgmt_addr, hint);
142	        if (reply_addrs.size() > 1) {
143	            UHD_LOG_ERROR("MPMD",
144	                "Could not resolve device hint \"" << hint.to_string()
145	                                                   << "\" to a unique device.");
146	            continue;
147	        } else if (reply_addrs.empty()) {
148	            continue;
149	        }
150	        UHD_LOG_TRACE("MPMD FIND", "Device responded: " << reply_addrs[0].to_string());
151	        found_devices.push_back(reply_addrs[0]);
152	    }
153	    if (found_devices.empty()) {
154	        return device_addrs_t();
155	    } else if (found_devices.size() == 1) {
156	        return found_devices;
157	    } else {
158	        return device_addrs_t(1, combine_device_addrs(found_devices));
159	    }
160	}
161	
162	device_addrs_t mpmd_find_with_bcast(const device_addr_t& hint)
163	{
164	    device_addrs_t addrs;
165	    if (hint.has_key("resource")) {
166	        return addrs;
167	    }
168	    UHD_LOG_TRACE(
169	        "MPMD FIND", "Broadcasting on all available interfaces to find MPM devices.");
170	    std::vector<std::future<device_addrs_t>> task_list;
171	    for (const auto& if_addr : transport::get_if_addrs()) {
172	        task_list.emplace_back(std::async(std::launch::async,
173	            [if_addr, hint]() { return mpmd_find_with_addr(if_addr.bcast, hint); }));
174	    }
175	    for (auto& task : task_list) {
176	        auto reply_addrs = task.get();
177	        addrs.insert(addrs.begin(), reply_addrs.begin(), reply_addrs.end());
178	    }
179	    return addrs;
180	}
181	
182	/*! Find MPM devices based on a hint
183	 *
184	 * There are two scenarios:
185	 *
186	 * 1) an addr or mgmt_addr was defined
187	 *
188	 * In this case, we will go through all the addrs. If they point to a device,
189	 * we will then compare the other attributes (serial, etc.). If they match,
190	 * the device goes into a list.
191	 *
192	 * 2) No addrs were defined
193	 *
194	 * In this case, we do a broadcast ping to see if any devices respond. After
195	 * that, we do the same matching.
196	 *
197	 */
198	device_addrs_t mpmd_find(const device_addr_t& hint_)
199	{
200	#ifdef HAVE_DPDK
201	    // Start DPDK so links come up
202	    if (hint_.has_key("use_dpdk")) {
203	        auto dpdk_ctx = uhd::transport::dpdk::dpdk_ctx::get();
204	        if (not dpdk_ctx->is_init_done()) {
205	            dpdk_ctx->init(hint_);
206	        }
207	    }
208	#endif
209	    device_addrs_t hints_without_prefs = separate_device_addr(hint_);
210	    device_addrs_t hints;
211	    for (size_t i = 0; i < hints_without_prefs.size(); i++) {
212	        hints.push_back(prefs::get_usrp_args(hints_without_prefs[i]));
213	    }
214	
215	    if (hint_.has_key("type")) {
216	        if (std::find(MPM_DEVICE_TYPES.cbegin(), MPM_DEVICE_TYPES.cend(), hint_["type"])
217	            == MPM_DEVICE_TYPES.cend()) {
218	            UHD_LOG_TRACE(
219	                "MPMD FIND", "Returning early, type does not match an MPM device.");
220	            return {};
221	        }
222	    }
223	    UHD_LOG_TRACE("MPMD FIND", "Finding with " << hints.size() << " different hint(s).");
224	
225	    // Scenario 1): User gave us at least one address
226	    if (not hints.empty()
227	        and (hints[0].has_key(xport::FIRST_ADDR_KEY)
228	             or hints[0].has_key(MGMT_ADDR_KEY))) {
229	        // Note: We don't try and connect to the devices in this mode, because
230	        // we only get here if the user specified addresses, and we assume she
231	        // knows what she's doing.
232	        return mpmd_find_with_addrs(hints);
233	    }
234	
235	    // Scenario 2): User gave us no address, and we need to broadcast
236	    if (hints.empty()) {
237	        hints.resize(1);
238	    }
239	    const auto bcast_mpm_devs = mpmd_find_with_bcast(hints[0]);
240	    UHD_LOG_TRACE(
241	        "MPMD FIND", "Found " << bcast_mpm_devs.size() << " device via broadcast.");
242	    const bool find_all = hint_.has_key(mpmd_impl::MPM_FINDALL_KEY);
243	    if (find_all) {
244	        UHD_LOG_TRACE("MPMD FIND",
245	            "User provided " << mpmd_impl::MPM_FINDALL_KEY
246	                             << ", will not "
247	                                "check devices for CHDR accessibility.");
248	    }
249	    // Filter found devices for those that we can actually talk to via CHDR
250	    device_addrs_t filtered_mpm_devs;
251	
252	    const bool check_reachability =
253	        hint_.has_key("mpm_check_reachability") ? uhd::cast::from_str<bool>(
254	            hint_.cast<std::string>("mpm_check_reachability", "Yes"))
255	                                                : uhd::prefs::mpm_check_reachability();
256	
257	    UHD_LOG_DEBUG("MPMD FIND",
258	        "Will " << (check_reachability ? "" : "not ")
259	                << "check devices for reachability");
260	
261	    if (check_reachability) {
262	        std::vector<std::future<boost::optional<device_addr_t>>> reachability_tasks;
263	        for (const auto& mpm_dev : bcast_mpm_devs) {
264	            if (mpm_dev.get(RPC_VERSION_KEY, DEFAULT_RPC_VERSION) == RPC_VERSION) {
265	                reachability_tasks.emplace_back(
266	                    std::async(std::launch::async, [mpm_dev]() {
267	                        return mpmd_mboard_impl::is_device_reachable(mpm_dev);
268	                    }));
269	            } else {
270	                reachability_tasks.emplace_back(std::async(std::launch::async,
271	                    []() { return boost::optional<device_addr_t>{}; }));
272	            }
273	        }
274	        // Variable i is used to index reachability_tasks as well as bcast_mpm_devs (both
275	        // of same size by construction), therefore using iterators here is less elegant.
276	        for (size_t i = 0; i < reachability_tasks.size(); ++i) {
277	            const auto reachable_device_addr = reachability_tasks[i].get();
278	            if (bool(reachable_device_addr)) {
279	                filtered_mpm_devs.push_back(reachable_device_addr.get());
280	            } else if (find_all) {
281	                filtered_mpm_devs.emplace_back(
282	                    flag_dev_as_unreachable(bcast_mpm_devs[i]));
283	            }
284	        }
285	    } else if (find_all) {
286	        filtered_mpm_devs = bcast_mpm_devs;
287	    } else {
288	        std::copy_if(bcast_mpm_devs.cbegin(),
289	            bcast_mpm_devs.cend(),
290	            std::back_inserter(filtered_mpm_devs),
291	            [](const device_addr_t& dev) {
292	                return dev.get(RPC_VERSION_KEY, DEFAULT_RPC_VERSION) == RPC_VERSION;
293	            });
294	    }
295	
296	    if (filtered_mpm_devs.empty() and not bcast_mpm_devs.empty()) {
297	        UHD_LOG_INFO("MPMD FIND",
298	            "Found MPM devices, but none are reachable for a UHD session. "
299	            "Specify "
300	                << mpmd_impl::MPM_FINDALL_KEY << " to find all devices.");
301	    }
302	
303	    return filtered_mpm_devs;
304	}
