36	/*! Return true if we can MPM ping a device via discovery service.
37	 */
38	bool is_pingable(const std::string& ip_addr, const std::string& udp_port)
39	{
40	    auto udp = uhd::transport::udp_simple::make_broadcast(ip_addr, udp_port);
41	    const std::string send_buf(uhd::mpmd::mpmd_impl::MPM_ECHO_CMD + " ping");
42	    std::vector<uint8_t> recv_buf;
43	    recv_buf.resize(send_buf.size(), ' ');
44	    udp->send(boost::asio::buffer(send_buf.c_str(), send_buf.size()));
45	    const size_t len = udp->recv(boost::asio::buffer(recv_buf), MPMD_PING_TIMEOUT);
46	    if (len == 0) {
47	        UHD_LOG_TRACE("MPMD", "Received no MPM ping, assuming device is unreachable.");
48	        return false;
49	    }
50	    if (len != send_buf.size()) {
51	        UHD_LOG_DEBUG("MPMD",
52	            "Received bad return packet on MPM ping. Assuming endpoint"
53	            " is not a valid MPM device.");
54	        return false;
55	    }
56	    if (std::memcmp((void*)&recv_buf[0], (void*)&send_buf[0], send_buf.size()) != 0) {
57	        UHD_LOG_DEBUG("MPMD",
58	            "Received invalid return packet on MPM ping. Assuming endpoint"
59	            " is not a valid MPM device.");
60	        return false;
61	    }
62	    return true;
63	}
