65	/*! Call init() on an MPM device.
66	 */
67	void init_device(uhd::rpc_client::sptr rpc, const uhd::device_addr_t mb_args)
68	{
69	    auto init_status = rpc->request_with_token<std::vector<std::string>>(
70	        MPMD_DEFAULT_INIT_TIMEOUT, "get_init_status");
71	    if (init_status[0] != "true") {
72	        throw uhd::runtime_error(
73	            std::string("Device is in bad state: ") + init_status[1]);
74	    }
75	
76	    // TODO maybe put this somewhere else?
77	    const std::set<std::string> key_blacklist{"serial", "claimed", "type", "rev", "addr"};
78	    std::map<std::string, std::string> mpm_device_args;
79	    for (const auto& key : mb_args.keys()) {
80	        if (not key_blacklist.count(key)) {
81	            mpm_device_args[key] = mb_args[key];
82	        }
83	    }
84	    if (not rpc->request_with_token<bool>(
85	            MPMD_DEFAULT_INIT_TIMEOUT, "init", mpm_device_args)) {
86	        throw uhd::runtime_error("Failed to initialize device.");
87	    }
