90	void measure_rpc_latency(
91	    uhd::rpc_client::sptr rpc, const size_t duration_ms = MPMD_MEAS_LATENCY_DURATION)
92	{
93	    const double alpha        = 0.99;
94	    const std::string payload = "1234567890";
95	    auto measure_once         = [payload, rpc]() {
96	        const auto start = std::chrono::steady_clock::now();
97	        rpc->request<std::string>("ping", payload);
98	        return (double)std::chrono::duration_cast<std::chrono::microseconds>(
99	            std::chrono::steady_clock::now() - start)
100	            .count();
101	    };
102	
103	    double max_latency = measure_once();
104	    double avg_latency = max_latency;
105	
106	    auto end_time =
107	        std::chrono::steady_clock::now() + std::chrono::milliseconds(duration_ms);
108	    size_t ctr = 1;
109	    while (std::chrono::steady_clock::now() < end_time) {
110	        const auto duration = measure_once();
111	        max_latency         = std::max(max_latency, duration);
112	        avg_latency         = avg_latency * alpha + (1 - alpha) * duration;
113	        ctr++;
114	        // Light throttle:
115	        std::this_thread::sleep_for(std::chrono::milliseconds(1));
116	    }
117	
118	    UHD_LOG_INFO("MPMD",
119	        "RPC latency (coarse estimate): Avg = " << avg_latency
120	                                                << " us, "
121	                                                   "Max = "
122	                                                << max_latency << ", n = " << ctr);
123	}
