125	/*! Forward entries from a list of dictionaries to UHD's native logging
126	 *  system.
127	 */
128	void forward_logs(log_buf_t&& log_buf)
129	{
130	    for (const auto& log_record : log_buf) {
131	        if (log_record.count("levelname") == 0 or log_record.count("message") == 0) {
132	            UHD_LOG_ERROR("MPMD", "Invalid logging structure returned from MPM device!");
133	            continue;
134	        }
135	        if (log_record.at("levelname") == "TRACE") {
136	            UHD_LOG_TRACE(log_record.at("name"), log_record.at("message"));
137	        } else if (log_record.at("levelname") == "DEBUG") {
138	            UHD_LOG_DEBUG(log_record.at("name"), log_record.at("message"));
139	        } else if (log_record.at("levelname") == "INFO") {
140	            UHD_LOG_INFO(log_record.at("name"), log_record.at("message"));
141	        } else if (log_record.at("levelname") == "WARNING") {
142	            UHD_LOG_WARNING(log_record.at("name"), log_record.at("message"));
143	        } else if (log_record.at("levelname") == "ERROR") {
144	            UHD_LOG_ERROR(log_record.at("name"), log_record.at("message"));
145	        } else if (log_record.at("levelname") == "CRITICAL") {
146	            UHD_LOG_FATAL(log_record.at("name"), log_record.at("message"));
147	        } else {
148	            UHD_LOG_ERROR("MPMD",
149	                "Invalid log level returned from MPM device: "
150	                "`" << log_record.at("levelname")
151	                    << "'");
152	        }
153	    }
154	}
