174	/******************************************************************************
175	 * Static Helpers
176	 *****************************************************************************/
177	boost::optional<device_addr_t> mpmd_mboard_impl::is_device_reachable(
178	    const device_addr_t& device_addr)
179	{
180	    UHD_LOG_TRACE(
181	        "MPMD", "Checking accessibility of device `" << device_addr.to_string() << "'");
182	    UHD_ASSERT_THROW(device_addr.has_key(MGMT_ADDR_KEY));
183	    const std::string rpc_addr = device_addr.get(MGMT_ADDR_KEY);
184	    const size_t rpc_port =
185	        device_addr.cast<size_t>(mpmd_impl::MPM_RPC_PORT_KEY, mpmd_impl::MPM_RPC_PORT);
186	    // 1) Read back device info
187	    dev_info device_info_dict;
188	    try {
189	        auto rpcc = uhd::rpc_client::make(rpc_addr, rpc_port);
190	        device_info_dict =
191	            rpcc->request<dev_info>(MPMD_SHORT_RPC_TIMEOUT, "get_device_info");
192	    } catch (const uhd::runtime_error& e) {
193	        UHD_LOG_DEBUG("MPMD", e.what());
194	        return boost::optional<device_addr_t>();
195	    } catch (...) {
196	        UHD_LOG_DEBUG("MPMD",
197	            "Unexpected exception when trying to query device info. Flagging "
198	            "device as unreachable.");
199	        return boost::optional<device_addr_t>();
200	    }
201	    // 2) Check for local device
202	    if (device_info_dict.count("connection")
203	        and device_info_dict.at("connection") == "local") {
204	        UHD_LOG_TRACE("MPMD", "Device is local, flagging as reachable.");
205	        return boost::optional<device_addr_t>(device_addr);
206	    }
207	    // 3) Check for network-reachable device
208	    // Note: This makes the assumption that devices will always allow RPC
209	    // connections on their CHDR addresses.
210	    const std::vector<std::string> addr_keys = {
211	        "second_addr", "addr", "third_addr", "fourth_addr"};
212	    bool addr_key_found = false;
213	    for (const auto& addr_key : addr_keys) {
214	        if (not device_info_dict.count(addr_key)) {
215	            continue;
216	        }
217	        addr_key_found              = true;
218	        const std::string chdr_addr = device_info_dict.at(addr_key);
219	        UHD_LOG_TRACE("MPMD", "Checking reachability via network addr " << chdr_addr);
220	        try {
221	            // First do an MPM ping -- there is some issue with rpclib that can
222	            // lead to indefinite timeouts
223	            const std::string mpm_discovery_port =
224	                device_addr.get(mpmd_impl::MPM_DISCOVERY_PORT_KEY,
225	                    std::to_string(mpmd_impl::MPM_DISCOVERY_PORT));
226	            if (!is_pingable(chdr_addr, mpm_discovery_port)) {
227	                UHD_LOG_TRACE("MPMD", "Cannot MPM ping, assuming device is unreachable.");
228	                continue;
229	            }
230	            UHD_LOG_TRACE("MPMD", "Was able to ping device, trying RPC connection.");
231	            auto chdr_rpcc = uhd::rpc_client::make(chdr_addr, rpc_port);
232	            auto dev_info_chdr =
233	                chdr_rpcc->request<dev_info>(MPMD_SHORT_RPC_TIMEOUT, "get_device_info");
234	            if (dev_info_chdr["serial"] != device_info_dict["serial"]) {
235	                UHD_LOG_DEBUG("MPMD",
236	                    boost::format("Connected to CHDR interface, but got wrong device. "
237	                                  "Tried to reach serial %s, got %s")
238	                        % device_info_dict["serial"] % dev_info_chdr["serial"]);
239	                continue;
240	            } else {
241	                UHD_LOG_TRACE("MPMD",
242	                    boost::format("Reachable device matches expected device (serial=%s)")
243	                        % device_info_dict["serial"]);
244	            }
245	            device_addr_t device_addr_copy = device_addr;
246	            device_addr_copy["addr"]       = chdr_addr;
247	            return boost::optional<device_addr_t>(device_addr_copy);
248	        } catch (...) {
249	            UHD_LOG_DEBUG(
250	                "MPMD", "Failed to reach device on network addr " << chdr_addr << ".");
251	        }
252	    }
253	    if (!addr_key_found) {
254	        // 4) get_device_info didn't give us CHDR info
255	        // This could be because the device isn't fully
256	        // initialized (e.g. e31x with a power save FPGA).
257	        // For UHD 4.0+, the mgmt interface will always
258	        // route CHDR packets when fully initialized
259	        // via Virtual NIC packet fowarding.
260	        device_addr_t device_addr_copy = device_addr;
261	        device_addr_copy["addr"]       = rpc_addr;
262	        return boost::optional<device_addr_t>(device_addr_copy);
263	    }
264	    // If everything fails, we probably can't talk to this chap.
265	    UHD_LOG_TRACE(
266	        "MPMD", "All reachability checks failed -- assuming device is not reachable.");
267	    return boost::optional<device_addr_t>();
268	}
