270	/*****************************************************************************
271	 * Structors
272	 ****************************************************************************/
273	mpmd_mboard_impl::mpmd_mboard_impl(
274	    const device_addr_t& mb_args_, const std::string& rpc_server_addr)
275	    : mb_args(mb_args_)
276	    , rpc(make_mpm_rpc_client(rpc_server_addr, mb_args_))
277	    , _claim_rpc(make_mpm_rpc_client(rpc_server_addr, mb_args, MPMD_CLAIMER_RPC_TIMEOUT))
278	    , _rpc_server_addr(rpc_server_addr)
279	{
280	    UHD_LOGGER_TRACE("MPMD") << "Initializing mboard, connecting to RPC server address: "
281	                             << rpc_server_addr
282	                             << " mboard args: " << mb_args.to_string();
283	
284	    _claimer_task = claim_device_and_make_task();
285	    if (mb_args_.has_key(MPMD_MEAS_LATENCY_KEY)) {
286	        measure_rpc_latency(rpc, MPMD_MEAS_LATENCY_DURATION);
287	    }
288	
289	    /// Get device info
290	    const auto device_info_dict = rpc->request<dev_info>("get_device_info");
291	    for (const auto& info_pair : device_info_dict) {
292	        device_info[info_pair.first] = info_pair.second;
293	    }
294	    UHD_LOG_DEBUG("MPMD", "MPM reports device info: " << device_info.to_string());
295	    /// Get dboard info
296	    const auto dboards_info = rpc->request<std::vector<dev_info>>("get_dboard_info");
297	    UHD_ASSERT_THROW(this->dboard_info.empty());
298	    for (const auto& dboard_info_dict : dboards_info) {
299	        uhd::device_addr_t this_db_info;
300	        for (const auto& info_pair : dboard_info_dict) {
301	            this_db_info[info_pair.first] = info_pair.second;
302	        }
303	        UHD_LOGGER_TRACE("MPMD")
304	            << "MPM reports dboard info for slot " << this->dboard_info.size() << ": "
305	            << this_db_info.to_string();
306	        this->dboard_info.push_back(this_db_info);
307	    }
308	
309	    if (!mb_args.has_key("skip_init")) {
310	        // Initialize mb_iface and mb_controller
311	        mb_iface = std::make_unique<mpmd_mb_iface>(mb_args, rpc);
312	        mb_ctrl  = std::make_shared<rfnoc::mpmd_mb_controller>(
313	            std::make_shared<uhd::usrp::mpmd_rpc>(rpc), device_info);
314	    } // Note -- when skip_init is used, these are not initialized, and trying
315	      // to use them will result in a null pointer dereference exception!
316	}
