331	void mpmd_mboard_impl::init()
332	{
333	    init_device(rpc, mb_args);
334	    auto need_mpm_reboot =
335	        rpc->request_with_token<std::vector<std::map<std::string, std::string>>>(
336	            "pop_host_tasks", "mpm_reboot");
337	    if (!need_mpm_reboot.empty()) {
338	        UHD_LOG_DEBUG("MPMD", "Bracing for potential loss of RPC server connection.");
339	        allow_claim_failure(true);
340	        UHD_LOGGER_INFO("MPMD") << "Rebooting MPM before device initialization!";
341	        auto id = rpc->request_with_token<int>("get_device_id");
342	        rpc->notify_with_token(MPMD_DEFAULT_REBOOT_TIMEOUT, "reset_timer_and_mgr");
343	        allow_claim_failure(false);
344	        reset_claim_loop();
345	        rpc->notify_with_token("set_device_id", id);
346	        init_device(rpc, mb_args);
347	    }
348	    mb_iface->init();
