359	/*****************************************************************************
360	 * Private methods
361	 ****************************************************************************/
362	bool mpmd_mboard_impl::claim()
363	{
364	    try {
365	        auto result = _claim_rpc->request_with_token<bool>("reclaim");
366	        // When _allow_claim_failure_flag goes from true to false, we still have
367	        // to wait for a successful reclaim before we can also set
368	        // _allow_claim_failure_latch to false, because we have no way of
369	        // synchronizing those events.
370	        // In other words, we might be setting allow_claim_failure back to false
371	        // too soon, but we have no way of knowing exactly when the right time
372	        // is.
373	        _allow_claim_failure_latch = _allow_claim_failure_flag.load();
374	        return result;
375	    } catch (const uhd::runtime_error& ex) {
376	        // Note: Any RPC error will raise a uhd::runtime_error. Other errors are
377	        // not handled here.
378	        if (_allow_claim_failure_latch) {
379	            UHD_LOG_DEBUG("MPMD", ex.what());
380	        } else {
381	            UHD_LOG_WARNING("MPMD", ex.what());
382	        }
383	        return _allow_claim_failure_latch;
384	    }
385	}
386	
387	uhd::task::sptr mpmd_mboard_impl::make_claim_loop_task()
388	{
389	    return uhd::task::make(
390	        [this] {
391	            auto now = std::chrono::steady_clock::now();
392	            if (not this->claim()) {
393	                throw uhd::value_error("mpmd device reclaiming loop failed!");
394	            } else {
395	                try {
396	                    this->dump_logs();
397	                } catch (const uhd::runtime_error&) {
398	                    UHD_LOG_WARNING("MPMD", "Could not read back log queue!");
399	                }
400	            }
401	            std::this_thread::sleep_until(
402	                now + std::chrono::milliseconds(MPMD_RECLAIM_INTERVAL_MS));
403	        },
404	        "mpmd_claimer_task");
405	}
406	
407	uhd::task::sptr mpmd_mboard_impl::claim_device_and_make_task()
408	{
409	    auto rpc_token = _claim_rpc->request<std::string>(
410	        "claim", mb_args.get("session_id", MPMD_DEFAULT_SESSION_ID));
411	    if (rpc_token.empty()) {
412	        throw uhd::value_error("mpmd device claiming failed!");
413	    }
414	    UHD_LOG_TRACE("MPMD", "Received claim token " << rpc_token);
415	    // Save token for both RPC clients
416	    _claim_rpc->set_token(rpc_token);
417	    rpc->set_token(rpc_token);
418	    _token = rpc_token;
419	    // Optionally clear log buf
420	    if (mb_args.has_key("skip_oldlog")) {
421	        try {
422	            this->dump_logs(true);
423	        } catch (const uhd::runtime_error&) {
424	            UHD_LOG_WARNING("MPMD", "Could not read back log queue!");
425	        }
426	    }
427	    return make_claim_loop_task();
428	}
