24	/*! Update a component using all required files. For example, when updating the FPGA image
25	 * (.bit or .bin), users can provide a new overlay image (DTS) to apply in addition.
26	 *
27	 * \param comps Vector of component files to be updated
28	 * \param mb Reference to the actual device
29	 */
30	uhd::usrp::component_files_t _update_component(
31	    const uhd::usrp::component_files_t& comps, mpmd_mboard_impl* mb)
32	{
33	    // Construct the arguments to update component
34	    std::vector<std::vector<uint8_t>> all_data;
35	    std::vector<std::map<std::string, std::string>> all_metadata;
36	    // Also construct a copy of just the metadata to store in the property tree
37	    uhd::usrp::component_files_t all_comps_copy;
38	
39	    bool just_reload = false;
40	    for (const auto& comp : comps) {
41	        // Make a map for update components args
42	        std::map<std::string, std::string> metadata;
43	        // Make a component copy to add to the property tree
44	        uhd::usrp::component_file_t comp_copy;
45	        // Copy the metadata
46	        for (const auto& key : comp.metadata.keys()) {
47	            metadata[key]           = comp.metadata[key];
48	            comp_copy.metadata[key] = comp.metadata[key];
49	            if (key == "just_reload") {
50	                just_reload = just_reload
51	                              | uhd::cast::from_str<bool>(metadata.at("just_reload"));
52	                //| (boost::to_lower_copy(metadata.at("just_reload")) == "true");
53	            }
54	        }
55	        // Copy to the update component args
56	        all_data.push_back(comp.data);
57	        all_metadata.push_back(metadata);
58	        // Copy to the property tree
59	        all_comps_copy.push_back(comp_copy);
60	    }
61	
62	    // If reset is specified we presume that the fpga/dts
63	    // components were updated in the last uhd::image_loader::load()
64	    // call and just reload the fpga/dts by resetting the peripheral
65	    // manager.
66	    if (just_reload) {
67	        mb->rpc->notify_with_token(MPMD_DEFAULT_INIT_TIMEOUT, "reset_timer_and_mgr");
68	        return all_comps_copy;
69	    }
70	
71	    // Now call update component
72	    mb->rpc->notify_with_token(
73	        MPMD_DEFAULT_INIT_TIMEOUT, "update_component", all_metadata, all_data);
74	    return all_comps_copy;
75	}
