77	/*
78	 * Query the device to get the metadata for desired component
79	 *
80	 * \param comp_name String component name
81	 * \param mb Reference to the actual device
82	 * \return component files containing the component metadata
83	 */
84	uhd::usrp::component_files_t _get_component_info(
85	    const std::string& comp_name, mpmd_mboard_impl* mb)
86	{
87	    UHD_LOG_TRACE("MPMD", "Getting component info for " << comp_name);
88	    const auto component_metadata = mb->rpc->request<std::map<std::string, std::string>>(
89	        "get_component_info", comp_name);
90	    // Copy the contents of the component metadata into a object we can return
91	    uhd::usrp::component_file_t return_component;
92	    auto& return_metadata = return_component.metadata;
93	    for (auto item : component_metadata) {
94	        return_metadata[item.first] = item.second;
95	    }
96	    return uhd::usrp::component_files_t{return_component};
97	}
98	} // namespace
99	
100	void mpmd_impl::init_property_tree(
101	    uhd::property_tree::sptr tree, fs_path mb_path, mpmd_mboard_impl* mb)
102	{
