53	void mpmd_mboard_impl::mpmd_mb_iface::init()
54	{
55	    UHD_LOG_TRACE("MPMD::MB_IFACE", "Requesting clock ifaces...");
56	    auto clock_ifaces = _rpc->request_with_token<clock_iface_list_t>("get_clocks");
57	    for (auto& clock : clock_ifaces) {
58	        auto iface = std::make_shared<uhd::rfnoc::clock_iface>(
59	            clock.at("name"), std::stod(clock.at("freq")), clock.count("mutable"));
60	        _clock_ifaces[clock.at("name")] = iface;
61	        iface->set_running(true);
62	        UHD_LOG_DEBUG("MPMD::MB_IFACE",
63	            "Adding clock iface `"
64	                << clock.at("name") << "`, frequency: " << (iface->get_freq() / 1e6)
65	                << " MHz, mutable: " << (iface->is_mutable() ? "Yes" : "No"));
66	    }
67	    UHD_LOG_TRACE("MPMD::MB_IFACE", "Requesting CHDR link types...");
68	    auto chdr_link_types =
69	        _rpc->request_with_token<std::vector<std::string>>("get_chdr_link_types");
70	    UHD_LOG_TRACE(
71	        "MPMD::MB_IFACE", "Found " << chdr_link_types.size() << " link type(s)");
72	    for (const auto& type : chdr_link_types) {
73	        UHD_LOG_TRACE("MPMD::MB_IFACE", "Trying link type `" << type << "'");
74	        const auto xport_info =
75	            _rpc->request_with_token<xport::mpmd_link_if_mgr::xport_info_list_t>(
76	                "get_chdr_link_options", type);
77	        // User may have specified: addr=192.168.10.2, second_addr=
78	        // MPM may have said: "my addresses are 192.168.10.2 and 192.168.20.2"
79	        if (_link_if_mgr->connect(type, xport_info, get_chdr_w())) {
80	            UHD_LOG_TRACE("MPMD::MB_IFACE", "Link type " << type << " successful.");
81	        }
82	    }
83	
84	    if (_link_if_mgr->get_num_links() == 0) {
85	        UHD_LOG_ERROR("MPMD::MB_IFACE", "No CHDR connection available!");
86	        throw uhd::runtime_error("No CHDR connection available!");
87	    }
88	
89	    for (size_t link_idx = 0; link_idx < _link_if_mgr->get_num_links(); link_idx++) {
90	        _local_device_id_map.emplace(allocate_device_id(), link_idx);
91	    }
92	}
