159	uhd::rfnoc::clock_iface::sptr mpmd_mboard_impl::mpmd_mb_iface::get_clock_iface(
160	    const std::string& clock_name, const uint8_t clock_idx)
161	{
162	    // In MPM, get_clocks() only provides clocks by a string index. For any clock
163	    // that is not known by name (i.e., the standard clocks such as radio_clk),
164	    // we simply pretend the index number as a string is its name.
165	    const bool auto_clk_idx   = clock_name == CLOCK_KEY_AUTO;
166	    const std::string clk_key = auto_clk_idx ? std::to_string(int(clock_idx))
167	                                             : clock_name;
168	    // clock_idx is a 6-bit value. If the clock index is 0, but we want to
169	    // auto-derive the clock attributes, then that means we have an old bitfile
170	    // where the clock ID bits are not populated.  (0 is the default value for
171	    // these bits prior to these changes). If we read back 0x3F (0b111111),
172	    // then that's the new default value for the clock ID. This means we have
173	    // built a bitfile off of up-to-date HDL, but the block never set the clock
174	    // info.
175	    if (auto_clk_idx && (clock_idx == 0x00 || clock_idx == 0x3F)) {
176	        UHD_LOG_THROW(uhd::not_implemented_error,
177	            "MPMD::MB_IFACE",
178	            "Automatic clock detection requested, but no valid clock index given ("
179	                << std::hex << clk_key << "). Make sure FPGA bitfile is up to date!");
180	    }
181	    if (_clock_ifaces.count(clk_key)) {
182	        UHD_LOG_TRACE(
183	            "MPMD::MB_IFACE", "Looking up clock info for clock ID '" << clk_key << "'");
184	        return _clock_ifaces.at(clk_key);
185	    } else {
186	        UHD_LOG_THROW(uhd::key_error,
187	            "MPMD::MB_IFACE",
188	            "Unable to look up clock '" << clk_key << "'. Invalid "
189	                                        << (auto_clk_idx ? "index" : "clock name"));
190	    }
191	}
