193	uhd::rfnoc::chdr_ctrl_xport::sptr mpmd_mboard_impl::mpmd_mb_iface::make_ctrl_transport(
194	    uhd::rfnoc::device_id_t local_device_id, const uhd::rfnoc::sep_id_t& local_epid)
195	{
196	    if (!_local_device_id_map.count(local_device_id)) {
197	        throw uhd::key_error(std::string("[MPMD::MB_IFACE] Cannot create control "
198	                                         "transport: Unknown local device ID ")
199	                             + std::to_string(local_device_id));
200	    }
201	    const size_t link_idx = _local_device_id_map.at(local_device_id);
202	    uhd::transport::send_link_if::sptr send_link;
203	    uhd::transport::recv_link_if::sptr recv_link;
204	    std::tie(send_link,
205	        std::ignore,
206	        recv_link,
207	        std::ignore,
208	        std::ignore,
209	        std::ignore,
210	        std::ignore) = _link_if_mgr->get_link(link_idx,
211	        uhd::transport::link_type_t::CTRL,
212	        uhd::device_addr_t());
213	
214	    /* Associate local device ID with the adapter */
215	    _adapter_map[local_device_id] = send_link->get_send_adapter_id();
216	
217	    auto io_srv = get_io_srv_mgr()->connect_links(
218	        recv_link, send_link, transport::link_type_t::CTRL);
219	
220	    auto pkt_factory = _link_if_mgr->get_packet_factory(link_idx);
221	    auto io_srv_mgr  = this->get_io_srv_mgr();
222	    auto xport       = uhd::rfnoc::chdr_ctrl_xport::make(io_srv,
223	        send_link,
224	        recv_link,
225	        pkt_factory,
226	        local_epid,
227	        send_link->get_num_send_frames(),
228	        recv_link->get_num_recv_frames(),
229	        send_link->get_send_frame_size(),
230	        [io_srv_mgr, send_link, recv_link]() {
231	            io_srv_mgr->disconnect_links(recv_link, send_link);
232	        });
233	    return xport;
234	}
