236	uhd::rfnoc::chdr_rx_data_xport::uptr
237	mpmd_mboard_impl::mpmd_mb_iface::make_rx_data_transport(
238	    uhd::rfnoc::mgmt::mgmt_portal& mgmt_portal,
239	    const uhd::rfnoc::sep_addr_pair_t& addrs,
240	    const uhd::rfnoc::sep_id_pair_t& epids,
241	    const uhd::rfnoc::sw_buff_t pyld_buff_fmt,
242	    const uhd::rfnoc::sw_buff_t mdata_buff_fmt,
243	    const uhd::device_addr_t& xport_args,
244	    const std::string& streamer_id)
245	{
246	    const uhd::rfnoc::sep_addr_t local_sep_addr = addrs.second;
247	
248	    if (!_local_device_id_map.count(local_sep_addr.first)) {
249	        throw uhd::key_error(std::string("[MPMD::MB_IFACE] Cannot create RX data "
250	                                         "transport: Unknown local device ID ")
251	                             + std::to_string(local_sep_addr.first));
252	    }
253	    const size_t link_idx = _local_device_id_map.at(local_sep_addr.first);
254	
255	    uhd::transport::send_link_if::sptr send_link;
256	    uhd::transport::recv_link_if::sptr recv_link;
257	    bool lossy_xport, packet_fc, enable_fc;
258	    size_t recv_buff_size;
259	    std::tie(send_link,
260	        std::ignore,
261	        recv_link,
262	        recv_buff_size,
263	        lossy_xport,
264	        packet_fc,
265	        enable_fc) = _link_if_mgr->get_link(link_idx,
266	        uhd::transport::link_type_t::RX_DATA,
267	        xport_args);
268	
269	    /* Associate local device ID with the adapter */
270	    _adapter_map[local_sep_addr.first] = send_link->get_send_adapter_id();
271	
272	    const uhd::rfnoc::stream_buff_params_t recv_capacity = {recv_buff_size,
273	        packet_fc ? static_cast<uint32_t>(recv_link->get_num_recv_frames())
274	                  : uhd::rfnoc::MAX_FC_CAPACITY_PKTS};
275	
276	    const double ratio = 1.0 / 32;
277	
278	    uhd::rfnoc::stream_buff_params_t fc_freq;
279	    if (enable_fc) {
280	        // Configure flow control frequency to use either bytes only or packets only
281	        if (packet_fc) {
282	            fc_freq = {uhd::rfnoc::MAX_FC_FREQ_BYTES,
283	                static_cast<uint32_t>(
284	                    std::ceil(recv_link->get_num_recv_frames() * ratio))};
285	        } else {
286	            fc_freq = {static_cast<uint64_t>(std::ceil(double(recv_buff_size) * ratio)),
287	                uhd::rfnoc::MAX_FC_FREQ_PKTS};
288	        }
289	    } else {
290	        fc_freq = {0, 0};
291	    }
292	
293	    stream_buff_params_t fc_headroom = {0, 0};
294	
295	    auto cfg_io_srv = get_io_srv_mgr()->connect_links(
296	        recv_link, send_link, transport::link_type_t::CTRL);
297	
298	    // Create the data transport
299	    auto pkt_factory = _link_if_mgr->get_packet_factory(link_idx);
300	    auto io_srv_mgr  = this->get_io_srv_mgr();
301	    auto fc_params   = chdr_rx_data_xport::configure_sep(cfg_io_srv,
302	        recv_link,
303	        send_link,
304	        pkt_factory,
305	        mgmt_portal,
306	        epids,
307	        pyld_buff_fmt,
308	        mdata_buff_fmt,
309	        recv_capacity,
310	        fc_freq,
311	        fc_headroom,
312	        lossy_xport,
313	        xport_args,
314	        [io_srv_mgr, recv_link, send_link]() {
315	            io_srv_mgr->disconnect_links(recv_link, send_link);
316	        });
317	
318	    cfg_io_srv.reset();
319	
320	    // Connect the links to an I/O service
321	    auto io_srv = get_io_srv_mgr()->connect_links(recv_link,
322	        send_link,
323	        transport::link_type_t::RX_DATA,
324	        get_default_io_srv_args(),
325	        xport_args,
326	        streamer_id);
327	
328	    auto rx_xport = std::make_unique<chdr_rx_data_xport>(io_srv,
329	        recv_link,
330	        send_link,
331	        pkt_factory,
332	        epids,
333	        recv_link->get_num_recv_frames(),
334	        fc_params,
335	        [io_srv_mgr, recv_link, send_link]() {
336	            io_srv_mgr->disconnect_links(recv_link, send_link);
337	        });
338	
339	    return rx_xport;
340	}
