427	std::map<std::string, uhd::device_addr_t>
428	mpmd_mboard_impl::mpmd_mb_iface::get_chdr_xport_adapters()
429	{
430	    if (!_has_remote_xport_capability) {
431	        return {};
432	    }
433	
434	    // Note: If MPM is capable, but the FPGA is not, then MPM will return an
435	    // empty list here.
436	    const auto xport_adapters = _rpc->request_with_token<
437	        std::map<std::string, std::map<std::string, std::string>>>(
438	        "get_chdr_xport_adapters");
439	
440	    // Convert to UHD data type and return
441	    std::map<std::string, uhd::device_addr_t> return_val;
442	    for (auto& adapter_info : xport_adapters) {
443	        return_val.insert({adapter_info.first, uhd::device_addr_t(adapter_info.second)});
444	    }
445	    return return_val;
446	}
