448	int mpmd_mboard_impl::mpmd_mb_iface::add_remote_chdr_route(const std::string& adapter_id,
449	    const uhd::rfnoc::sep_id_t epid,
450	    const uhd::device_addr_t& route_args)
451	{
452	    if (!_has_remote_xport_capability) {
453	        throw uhd::not_implemented_error("This version of MPM does not have the "
454	                                         "capability to add remote CHDR routes!");
455	    }
456	    const auto adapters = get_chdr_xport_adapters();
457	    if (!adapters.count(adapter_id)) {
458	        throw uhd::value_error(
459	            "Invalid adapter for creating a remote route: " + adapter_id);
460	    }
461	    std::map<std::string, std::string> route_args_map;
462	    for (const auto& key : route_args.keys()) {
463	        route_args_map[key] = route_args.get(key);
464	    }
465	    return _rpc->request_with_token<int>(
466	        "add_remote_chdr_route", adapter_id, epid, route_args_map);
467	}
