    }

    //! Reference the actual RPC client
    std::shared_ptr<rpc::client> _client;
    //! If set, this is the command that will retrieve an error
    const std::string _get_last_error_cmd;
    uint64_t _default_timeout_ms;
    std::string _token;
    std::mutex _mutex;
};

} /* namespace uhd */

